// Elasticsearch client configuration
@Configuration
public class ElasticsearchClientConfig {

    @Bean
    public RestHighLevelClient elasticsearchClient() {
        final CredentialsProvider credentialsProvider = new BasicCredentialsProvider();
        credentialsProvider.setCredentials(AuthScope.ANY, new UsernamePasswordCredentials("elastic", "changeme"));

        final HttpHost[] elasticsearchHosts = new HttpHost[]{new HttpHost("localhost", 9200, "http")};

        final RequestOptions requestOptions = RequestOptions.DEFAULT.toBuilder()
                .setCredentialsProvider(credentialsProvider)
                .build();

        return new RestHighLevelClient(RestClient.builder(elasticsearchHosts).setRequestConfigCallback(
                builder -> builder.setConnectTimeout(30000).setSocketTimeout(30000).setNodeSelector(new LocalNodeSelector())
        ).setDefaultHeaders(Collections.singletonMap("Content-Type", "application/json")).build(), requestOptions);
    }
}

// Product indexing service
@Service
public class ProductIndexService {

    private final RestHighLevelClient elasticsearchClient;

    public ProductIndexService(RestHighLevelClient elasticsearchClient) {
        this.elasticsearchClient = elasticsearchClient;
    }

    public void indexProduct(Product product) {
        try {
            elasticsearchClient.index(new IndexRequest("products").id(product.getId()).source(product), RequestOptions.DEFAULT);
        } catch (Exception e) {
            // handle exception
        }
    }
}

// Full-text search service
@Service
public class ProductSearchService {

    private final RestHighLevelClient elasticsearchClient;

    public ProductSearchService(RestHighLevelClient elasticsearchClient) {
        this.elasticsearchClient = elasticsearchClient;
    }

    public List<Product> searchProducts(String query) {
        try {
            SearchRequest searchRequest = new SearchRequest("products").source(new SearchSourceBuilder().query(QueryBuilders.matchQuery("name", query)));
            SearchResponse searchResponse = elasticsearchClient.search(searchRequest, RequestOptions.DEFAULT);
            return Arrays.asList(searchResponse.getHits().map(h -> h.getSourceAsObject(Product.class)));
        } catch (Exception e) {
            // handle exception
        }
    }
}

// Faceted navigation service
@Service
public class ProductFacetService {

    private final RestHighLevelClient elasticsearchClient;

    public ProductFacetService(RestHighLevelClient elasticsearchClient) {
        this.elasticsearchClient = elasticsearchClient;
    }

    public Map<String, List<String>> getFacets(String category) {
        try {
            SearchRequest searchRequest = new SearchRequest("products").source(new SearchSourceBuilder().query(QueryBuilders.matchQuery("category", category)).facets(TermsFacetBuilder.of("category").field("category")));
            SearchResponse searchResponse = elasticsearchClient.search(searchRequest, RequestOptions.DEFAULT);
            return searchResponse.getFacets().get("category").getBuckets().stream().collect(Collectors.toMap(TermsFacet.Bucket::getKey, b -> b.getDocCountList()));
        } catch (Exception e) {
            // handle exception
        }
    }
}